<?php
/**
 * Helpers de formatage génériques (préfixe wpis_).
 *
 * @package HelloImmoSync
 */

defined( 'ABSPATH' ) || exit;

/**
 * Formate un nombre selon la locale FR (séparateur de milliers par espace).
 *
 * @param mixed $value    Valeur numérique.
 * @param int   $decimals Décimales.
 * @return string
 */
function wpis_format_number( $value, $decimals = 0 ) {
	if ( '' === $value || null === $value || ! is_numeric( $value ) ) {
		return '';
	}
	// Certaines locales (fr_BE…) définissent le séparateur de milliers comme
	// l'entité « &nbsp; » : on la convertit en espace insécable réel pour éviter
	// une double-échappement (« 1&amp;nbsp;200 ») lors d'un esc_html() en aval.
	return str_replace( '&nbsp;', "\xc2\xa0", number_format_i18n( (float) $value, $decimals ) );
}

/**
 * Formate une surface ("236 m²"). Retourne '' si vide ou nulle.
 *
 * @param mixed  $value Surface.
 * @param string $unit  Unité.
 * @return string
 */
function wpis_format_area( $value, $unit = 'm²' ) {
	if ( ! is_numeric( $value ) || (float) $value <= 0 ) {
		return '';
	}
	$formatted = wpis_format_number( $value );
	return trim( $formatted . ' ' . $unit );
}

/**
 * Formate un montant monétaire ("1 200 €"). Retourne '' si vide ou nulle.
 *
 * @param mixed  $value    Montant.
 * @param string $currency Devise (symbole ou code).
 * @param string $suffix   Suffixe optionnel (ex. "/ mois").
 * @return string
 */
function wpis_format_price_value( $value, $currency = '€', $suffix = '' ) {
	if ( ! is_numeric( $value ) || (float) $value <= 0 ) {
		return '';
	}
	$out = trim( wpis_format_number( $value ) . ' ' . $currency );
	return '' !== $suffix ? trim( $out . ' ' . $suffix ) : $out;
}

/**
 * Formate une distance en mètres ("150 m", "1,2 km"). Retourne '' si vide/nulle.
 *
 * @param mixed $meters Distance en mètres.
 * @return string
 */
function wpis_format_distance( $meters ) {
	if ( ! is_numeric( $meters ) || (float) $meters <= 0 ) {
		return '';
	}
	$meters = (float) $meters;
	if ( $meters >= 1000 ) {
		return wpis_format_number( $meters / 1000, 1 ) . ' km';
	}
	return wpis_format_number( $meters ) . ' m';
}

